#include<bits/stdc++.h>
using namespace std;
long long n,m;
struct node
{
    long long p,v;
    bool operator<(const node&b)const
    {
        return p<b.p;
    }
}a[100010];
long long solve(long long l,long long r)
{
    long long now=0,ans=0;
    if(a[l].p==1)
    {
        for(long long i=l;i<=r;i++)
        {
            now^=a[i].v;
            ans+=now;
        }
    }
    else
    {
        for(long long i=30;i>=0;i--)
        {
            long long cnt[2],tot[2];
            cnt[0]=tot[0]=0;
            cnt[1]=tot[1]=1;
            for(long long j=0;j<=1;j++)
            {
                for(long long k=l;k<=r;k++)
                {
                    tot[j]^=(a[k].v>>i)&1;
                    cnt[j]+=tot[j];
                }
            }
            ans+=(1<<i)*min(cnt[0],cnt[1]);
        }
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&a[i].p,&a[i].v);
    }
    sort(a+1,a+1+m);
    long long now=1,ans=0;
    while(now<=m)
    {
        long long lst=now;
        while(a[now].p+1==a[now+1].p)
        {
            now++;
        }
        ans+=solve(lst,now);
        now++;
    }
    printf("%lld",ans);
    return 0;
}
